# Create IdP sub-app under surface
idp_app = typer.Typer(
    name="idp",
    help="Identity Provider configuration for OAuth-based user access control",
    no_args_is_help=True,
)
surface_app.add_typer(idp_app)


# Provider-specific JWKS URI templates
PROVIDER_JWKS_TEMPLATES: dict[str, str] = {
    "keycloak": "{issuer}/protocol/openid-connect/certs",
    "auth0": "{issuer}/.well-known/jwks.json",
    "okta": "{issuer}/oauth2/v1/keys",
    "google": "https://www.googleapis.com/oauth2/v3/certs",
}


def _discover_jwks_uri(issuer: str, verify_ssl: bool = True) -> str | None:
    """Discover JWKS URI from OpenID Connect well-known endpoint.

    Args:
        issuer: OAuth issuer URL
        verify_ssl: Whether to verify SSL certificates

    Returns:
        JWKS URI if discovered, None otherwise
    """
    import httpx

    # Normalize issuer URL
    issuer = issuer.rstrip("/")
    well_known_url = f"{issuer}/.well-known/openid-configuration"

    try:
        with httpx.Client(verify=verify_ssl, timeout=10.0) as client:
            response = client.get(well_known_url)
            if response.status_code == 200:
                config = response.json()
                return config.get("jwks_uri")
    except Exception:
        pass

    return None


def _build_jwks_uri(issuer: str, provider: str | None, jwks_uri: str | None, verify_ssl: bool) -> str:
    """Build JWKS URI from issuer, provider shortcut, or explicit value.

    Args:
        issuer: OAuth issuer URL
        provider: Provider shortcut (keycloak, auth0, okta, azure, google)
        jwks_uri: Explicit JWKS URI (overrides auto-discovery)
        verify_ssl: Whether to verify SSL certificates

    Returns:
        JWKS URI string
    """
    # Explicit JWKS URI takes precedence
    if jwks_uri:
        return jwks_uri

    # Normalize issuer
    issuer = issuer.rstrip("/")

    # Use provider template if available
    if provider and provider in PROVIDER_JWKS_TEMPLATES:
        template = PROVIDER_JWKS_TEMPLATES[provider]
        return template.format(issuer=issuer)

    # Try OIDC discovery
    discovered = _discover_jwks_uri(issuer, verify_ssl)
    if discovered:
        return discovered

    # Fallback to common pattern
    return f"{issuer}/.well-known/jwks.json"


def _parse_claim_mappings(mappings: list[str] | None) -> dict[str, str]:
    """Parse claim mapping strings into a dictionary.

    Args:
        mappings: List of "access_tag=jwt_claim" strings

    Returns:
        Dictionary mapping access tag names to JWT claim paths
    """
    if not mappings:
        return {}

    result: dict[str, str] = {}
    for mapping in mappings:
        if "=" not in mapping:
            console.print(
                f"[bold yellow]Warning:[/bold yellow] Invalid claim mapping '{mapping}' "
                "(expected format: 'access_tag=jwt_claim'), skipping"
            )
            continue
        access_tag, jwt_claim = mapping.split("=", 1)
        result[access_tag.strip()] = jwt_claim.strip()

    return result


def _load_idp_config_from_file(file_path: Path) -> dict[str, Any]:
    """Load IdP configuration from JSON file.

    Args:
        file_path: Path to JSON file

    Returns:
        IdP configuration dictionary
    """
    import json

    if not file_path.exists():
        console.print(f"[bold red]Error:[/bold red] File not found: {file_path}")
        raise typer.Exit(code=1)

    try:
        with open(file_path) as f:
            return json.load(f)
    except json.JSONDecodeError as e:
        console.print(f"[bold red]Error:[/bold red] Invalid JSON in {file_path}: {e}")
        raise typer.Exit(code=1) from e


@idp_app.command("configure")
def idp_configure(
    ctx: typer.Context,
    engine_id: Annotated[str, typer.Argument(help="Context surface ID")],
    issuer: Annotated[
        str | None,
        typer.Option(
            "--issuer", "-i",
            help="OAuth issuer URL (e.g., 'https://auth.example.com/realms/my-realm')"
        )
    ] = None,
    provider: Annotated[
        str | None,
        typer.Option(
            "--provider", "-P",
            help="Provider shortcut: keycloak, auth0, okta, azure, google"
        )
    ] = None,
    audience: Annotated[
        str | None,
        typer.Option("--audience", "-a", help="Expected token audience (client ID)")
    ] = None,
    jwks_uri: Annotated[
        str | None,
        typer.Option("--jwks-uri", help="JWKS endpoint URL (auto-discovered if not specified)")
    ] = None,
    user_claim: Annotated[
        str,
        typer.Option("--user-claim", help="JWT claim to use as user identifier")
    ] = "sub",
    claim_mapping: Annotated[
        list[str] | None,
        typer.Option(
            "--claim-mapping", "-m",
            help="Map JWT claim to access tag (repeatable): 'access_tag=jwt_claim'"
        )
    ] = None,
    require_token: Annotated[
        bool,
        typer.Option("--require-token", help="Require user token for all requests")
    ] = False,
    no_verify_ssl: Annotated[
        bool,
        typer.Option("--no-verify-ssl", help="Skip SSL verification (development only)")
    ] = False,
    allow_insecure: Annotated[
        bool,
        typer.Option("--allow-insecure", help="Allow HTTP URLs for issuer/JWKS (development only)")
    ] = False,
    from_file: Annotated[
        Path | None,
        typer.Option("--from-file", "-f", help="Import IdP configuration from JSON file")
    ] = None,
    admin_key: Annotated[
        str | None,
        typer.Option("--admin-key", help="Admin API key")
    ] = None,
) -> None:
    """Configure OAuth identity provider for a context surface.

    Enables user-level access control by validating JWT tokens from an external
    identity provider and extracting access tags from claims.

    [bold]Examples:[/bold]

    Basic usage (auto-discovers JWKS):
        cce engine idp configure ce-123 --issuer "https://auth.example.com/realms/my-realm"

    With audience and claim mappings:
        cce engine idp configure ce-123 \\
            --issuer "https://auth.example.com/realms/my-realm" \\
            --audience "my-client-id" \\
            --claim-mapping "department=department" \\
            --claim-mapping "tenant=tenant_id"

    Using provider shortcut:
        cce engine idp configure ce-123 \\
            --provider keycloak \\
            --issuer "https://keycloak.example.com/realms/my-realm"

    Import from file:
        cce engine idp configure ce-123 --from-file ./idp-config.json
    """
    from context_surfaces.cli.services.auth_helper import resolve_auth_with_refresh

    cli_ctx = get_cli_context(ctx)
    profile_config = cli_ctx.config_manager.load_config().profiles[cli_ctx.profile]

    # Resolve authentication
    auth = resolve_auth_with_refresh(
        admin_key, cli_ctx.credential_manager, profile_config,
        cli_ctx.config_manager, cli_ctx.profile
    )

    # Build IdP configuration
    if from_file:
        # Load from file
        idp_config = _load_idp_config_from_file(from_file)
    else:
        # Build from CLI options
        if not issuer:
            console.print(
                "[bold red]Error:[/bold red] --issuer is required unless using --from-file"
            )
            raise typer.Exit(code=1)

        # Validate provider if specified
        if provider and provider not in PROVIDER_JWKS_TEMPLATES and provider != "azure":
            console.print(
                f"[bold red]Error:[/bold red] Unknown provider '{provider}'. "
                f"Valid options: {', '.join(PROVIDER_JWKS_TEMPLATES.keys())}, azure"
            )
            raise typer.Exit(code=1)

        # Build JWKS URI
        resolved_jwks_uri = _build_jwks_uri(issuer, provider, jwks_uri, not no_verify_ssl)

        # Parse claim mappings
        access_tag_claims = _parse_claim_mappings(claim_mapping)

        idp_config = {
            "enabled": True,
            "issuer": issuer.rstrip("/"),
            "jwks_uri": resolved_jwks_uri,
            "audience": audience,
            "user_claim": user_claim,
            "access_tag_claims": access_tag_claims,
            "require_user_token": require_token,
            "allow_insecure": allow_insecure,
        }

    async def _configure() -> None:
        from context_surfaces import (
            ContextSurfacesClient,
            UpdateContextSurfaceRequest,
        )

        api_url = profile_config.api_url

        async with ContextSurfacesClient(api_url) as client:
            # Update context surface with IdP configuration
            from context_surfaces.models import IdentityProviderConfig

            # Create IdentityProviderConfig from dict
            idp_config_obj = IdentityProviderConfig(
                enabled=idp_config.get("enabled", True),
                issuer=idp_config["issuer"],
                jwks_uri=idp_config["jwks_uri"],
                audience=idp_config.get("audience"),
                user_claim=idp_config.get("user_claim", "sub"),
                access_tag_claims=idp_config.get("access_tag_claims", {}),
                require_user_token=idp_config.get("require_user_token", False),
                allow_insecure=idp_config.get("allow_insecure", False),
            )

            await client.update_context_surface(
                engine_id,
                UpdateContextSurfaceRequest(identity_provider=idp_config_obj),
                admin_key=auth.api_key,
                session_id=auth.session_id,
                csrf_token=auth.csrf_token,
            )

            console.print(f"[green]✓[/green] Identity Provider configured for context surface '{engine_id}'")
            console.print()
            console.print("[bold]Configuration:[/bold]")
            console.print(f"  Enabled: {idp_config_obj.enabled}")
            console.print(f"  Issuer: {idp_config_obj.issuer}")
            console.print(f"  JWKS URI: {idp_config_obj.jwks_uri}")
            if idp_config_obj.audience:
                console.print(f"  Audience: {idp_config_obj.audience}")
            console.print(f"  User Claim: {idp_config_obj.user_claim}")
            console.print(f"  Require Token: {idp_config_obj.require_user_token}")
            if idp_config_obj.access_tag_claims:
                console.print("  Access Tag Mappings:")
                for tag, claim in idp_config_obj.access_tag_claims.items():
                    console.print(f"    {tag} → {claim}")

    try:
        asyncio.run(_configure())
    except Exception as e:
        handle_error(e)
        raise typer.Exit(code=1) from e


