                console.print(f"  User Claim: {idp.user_claim}")
                console.print(f"  Require Token: {'Yes' if idp.require_user_token else 'No'}")
                if idp.access_tag_claims:
                    console.print("  Access Tag Mappings:")
                    for tag, claim in idp.access_tag_claims.items():
                        console.print(f"    {tag} → {claim}")
                else:
                    console.print("  Access Tag Mappings: [dim]None[/dim]")
                console.print()
